	got, warns := discoverTargets(t.TempDir(), bundledAdapters())
	if len(got) != 0 {
		t.Fatalf("discoverTargets = %v, want empty", got)
	}
	if len(warns) != 0 {
		t.Fatalf("unexpected warnings: %v", warns)
