244	// looksLikeLocalPath reports whether s is a filesystem path rather than a
245	// git URL. A string is a URL only if it carries a scheme (foo://) or is
246	// scp-style (user@host:path); everything else — POSIX absolute/relative
247	// paths, bare names, and Windows drive paths (C:\repo) — is treated as a
248	// local path. The default is "local", because a git remote always has a
249	// recognizable scheme or scp shape, whereas local paths take many forms.
250	func looksLikeLocalPath(s string) bool {
251		s = strings.TrimSpace(s)
252		if s == "" {
253			return false
254		}
255		// Scheme-bearing URL: https://, ssh://, git://, file://, etc.
256		if schemeRE.MatchString(s) {
257			return false
258		}
259		// scp-style remote: user@host:path (an '@' before the first ':').
260		if at := strings.IndexByte(s, '@'); at >= 0 {
261			if colon := strings.IndexByte(s, ':'); colon > at {
262				return false
263			}
264		}
265		// Windows drive path (C:\ or C:/) is local, even though it contains ':'.
266		if winDriveRE.MatchString(s) {
267			return true
268		}
269		// A bare "host:path" with no '@' and no drive letter is ambiguous; treat
270		// a single-letter prefix before ':' as a Windows drive (handled above)
271		// and anything else with a ':' as an scp-style host:path remote.
272		if strings.Contains(s, ":") {
273			return false
274		}
275		// No scheme, no scp shape, no ambiguous colon → a local path
276		// (absolute, ./, ../, ~, or a bare relative name like "repo/sub").
277		return true
278	}
