// key builds a rune keypress message.
func key(r rune) tea.KeyMsg { return tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{r}} }

func typeString(m *initModel, s string) {
	for _, r := range s {
		m.Update(key(r))
