func (m *initModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	key, isKey := msg.(tea.KeyMsg)
	if isKey && (key.Type == tea.KeyCtrlC || key.Type == tea.KeyEsc) {
		m.quitting = true
		m.committed = false
		return m, tea.Quit
